-- `predicate(element)` returns true.
local function filter<T>(t: {T}, predicate: (T) -> boolean): {T}

-- Given an array of integers `t`, returns a new array with duplicate values
-- removed. The first occurrence of each value is kept; order is preserved.
local function unique(t: {number}): {number}

