local function interpolate(template: string, values: {[string]: any}): string
	return (template:gsub("{(%w+)}", function(key)
		local v = values[key]
		return if v ~= nil then tostring(v) else "{" .. key .. "}"
	end))
end

local Signal = {}
Signal.__index = Signal

function Signal.new()
	return setmetatable({ _connections = {} :: {{fn: (...any)->(), once: boolean}} }, Signal)
end

function Signal:Connect(fn: (...any) -> ())
	local entry = {fn = fn, once = false}
	table.insert(self._connections, entry)
	return {
		Disconnect = function()
			for i, c in self._connections do
				if c == entry then
					table.remove(self._connections, i)
					return
				end
			end
		end
	}
end

function Signal:Once(fn: (...any) -> ())
	local entry = {fn = fn, once = true}
	table.insert(self._connections, entry)
	return {
		Disconnect = function()
			for i, c in self._connections do
				if c == entry then table.remove(self._connections, i) return end
			end
		end
	}
end

function Signal:Fire(...: any)
	for i = #self._connections, 1, -1 do
		local c = self._connections[i]
		if c.once then table.remove(self._connections, i) end
		c.fn(...)
	end
end

